Code.Terraform:
```hcl
# 启用了网络隔离的 SageMaker 模型
resource "aws_sagemaker_model" "<example_resource_name>" {
  name               = "<example_resource_name>"
  execution_role_arn = "<example_resource_arn>"

  primary_container {
    image = "<example_image>"
  }

  enable_network_isolation = true  # 关键：启用网络隔离以通过检查
}
```
